INSERT INTO frameworks (id, organization_id, name, description, version, is_default) VALUES ('0147d901-984d-44c1-a08f-94f919659596', 'e802a6cb-6cfa-4a7c-aba6-2038490fb899', 'MUDEK 2024', 'MÜDEK accreditation framework aligned with EUR-ACE standards. Evaluates engineering program outcomes across technical competency, design, communication, and teamwork dimensions.', '1.0', true) ON CONFLICT DO NOTHING;
INSERT INTO frameworks (id, organization_id, name, description, version, is_default) VALUES ('efe329b2-0a62-4279-a7d1-627abe557321', 'b94595d6-710c-4302-ad1b-11f4d216e028', 'ABET 2024', 'ABET Computing Accreditation Commission framework. Assesses student outcomes in computing knowledge, problem analysis, solution design, communication, and professional ethics.', '1.0', true) ON CONFLICT DO NOTHING;
INSERT INTO frameworks (id, organization_id, name, description, version, is_default) VALUES ('824ead2b-7676-4297-a6e1-507869f5f299', 'd8214e32-d30f-4a0c-aee5-1c6fa0d41336', 'Competition Framework 2026', 'TEKNOFEST ulusal teknoloji yarışması değerlendirme çerçevesi. Havacılık ve robotik kategorilerinde teknolojik yenilik, proje fizibilitesi, prototip kalitesi ve takım sunumu esas alınarak değerlendirilir.', '2026', true) ON CONFLICT DO NOTHING;
INSERT INTO frameworks (id, organization_id, name, description, version, is_default) VALUES ('cf0b03e5-576d-4961-a0cc-f86b7852b85f', '088f5054-c9df-4c7f-a679-c1321524f250', 'Research Competition Framework', 'TÜBİTAK 2204-A ulusal lise öğrencileri araştırma projeleri yarışması değerlendirme çerçevesi. Bilimsel yöntem, araştırma derinliği, özgünlük ve sözlü savunma kalitesi ölçütlerine göre puanlanır.', '2204A', true) ON CONFLICT DO NOTHING;
INSERT INTO frameworks (id, organization_id, name, description, version, is_default) VALUES ('8df4448a-b223-4569-a92e-4c81b669b065', 'ff81ecf1-13ac-44b2-a331-0a207a8c7184', 'Design Contest Framework', 'IEEE AP-S Student Design Contest framework. Evaluates antenna design performance, technical documentation quality, oral presentation, and adherence to contest specifications.', '1.0', true) ON CONFLICT DO NOTHING;
INSERT INTO frameworks (id, organization_id, name, description, version, is_default) VALUES ('30357731-811e-4875-a60b-1d78e969b144', '2060c696-71f7-4a57-a7c9-d3bcdc9db763', 'Mission Framework', 'CanSat Competition mission evaluation framework. Assesses satellite container design, mission objective completion, telemetry data quality, and post-flight analysis report.', '2025', true) ON CONFLICT DO NOTHING;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('128e43e4-2016-4b3a-a41a-0e4856a3f593', '0147d901-984d-44c1-a08f-94f919659596', 'MDK 1.2', 'Adequate knowledge in mathematics, science and engineering', 'Demonstrate sufficient knowledge of mathematics, natural sciences, and engineering fundamentals to solve complex engineering problems.', 1) ON CONFLICT DO NOTHING;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('3f794c86-281a-4f11-a496-dba69369ad00', '0147d901-984d-44c1-a08f-94f919659596', 'MDK 2', 'Ability to formulate and solve complex engineering problems', 'Identify, define, formulate, and solve complex engineering problems by selecting and applying appropriate analysis and modeling methods.', 2) ON CONFLICT DO NOTHING;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('0c2156fb-1a3b-4939-ab0d-ad721e790312', '0147d901-984d-44c1-a08f-94f919659596', 'MDK 3', 'Ability to design solutions under realistic constraints', 'Design complex systems, processes, devices, or products under realistic constraints, applying creative and modern design methods to meet identified needs.', 3) ON CONFLICT DO NOTHING;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('88c82546-fa1d-4abe-aed2-bb7f97199aaf', '0147d901-984d-44c1-a08f-94f919659596', 'MDK 8.1', 'Ability to function effectively in disciplinary teams', 'Function effectively as a member or leader in disciplinary teams, taking individual responsibility within face-to-face, remote, or hybrid settings.', 4) ON CONFLICT DO NOTHING;
