INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('927c6ee5-bb03-44b8-afda-2a97f4272add', 'cf0b03e5-576d-4961-a0cc-f86b7852b85f', 'RC-1', 'Originality and Creativity', 'Demonstrate original thinking addressing genuine gaps in scientific literature.', 1) ON CONFLICT DO NOTHING;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('8258a7a0-3329-4b87-a2f9-ed57789c5d5f', 'cf0b03e5-576d-4961-a0cc-f86b7852b85f', 'RC-2', 'Scientific Method', 'Apply rigorous scientific methodology including proper experimental design.', 2) ON CONFLICT DO NOTHING;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('29460c43-c2cc-42dc-a55c-9ae4ac05cb0f', 'cf0b03e5-576d-4961-a0cc-f86b7852b85f', 'RC-3', 'Results and Recommendations', 'Present clear, reproducible results with actionable recommendations.', 3) ON CONFLICT DO NOTHING;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('5971a865-48c8-45c7-a1fe-42276ca9c27c', 'cf0b03e5-576d-4961-a0cc-f86b7852b85f', 'RC-4', 'Applicability and Feasibility', 'Demonstrate practical applicability for real-world implementation.', 4) ON CONFLICT DO NOTHING;
