INSERT INTO periods (id, organization_id, framework_id, name, season, description, start_date, end_date, is_current, is_locked, is_visible, snapshot_frozen_at, activated_at, updated_at) VALUES ('a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'e802a6cb-6cfa-4a7c-aba6-2038490fb899', '0147d901-984d-44c1-a08f-94f919659596', 'Spring 2026', 'Spring', 'EE 491/492 Senior Design — 1-Day Poster Evaluation', '2026-06-11', '2026-06-11', true, false, true, (timestamp '2026-06-11 09:00:00' - interval '24 hours 0 minutes'), (timestamp '2026-06-11 09:00:00' + interval '34 hours 47 minutes'), (timestamp '2026-06-11 09:00:00' - interval '20 hours 0 minutes')) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('787e905a-a2da-431e-af63-00cea2ea7bb5', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'c88501db-537c-448f-a967-fd759b41915b', 'technical', 'Technical Content', 'Technical', 'Evaluates the depth, correctness, and originality of the engineering work itself — independent of how well it is communicated. It assesses whether the team has applied appropriate engineering knowledge, justified their design decisions, and demonstrated real technical mastery.', 30, 30, '#F59E0B', '[{"min":27,"max":30,"label":"Excellent","description":"Problem is clearly defined with strong motivation. Design decisions are well-justified with engineering depth. Originality and mastery of relevant tools or methods are evident."},{"min":21,"max":26,"label":"Good","description":"Design is mostly clear and technically justified. Engineering decisions are largely supported."},{"min":13,"max":20,"label":"Developing","description":"Problem is stated but motivation or technical justification is insufficient."},{"min":0,"max":12,"label":"Insufficient","description":"Vague problem definition and unjustified decisions. Superficial technical content."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('25fdf203-ff5f-4c31-ab09-3ac8bd726e65', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', '91d2ee22-2b0f-48eb-ac87-5e1fed001650', 'design', 'Written Communication', 'Written', 'Evaluates how effectively the team communicates their project in written and visual form on the poster — including layout, information hierarchy, figure quality, and the clarity of technical content for a mixed audience (engineers and non-engineers alike).', 30, 30, '#22C55E', '[{"min":27,"max":30,"label":"Excellent","description":"Poster layout is intuitive with clear information flow. Visuals are fully labelled and high quality. Technical content is presented in a way accessible to both technical and non-technical readers."},{"min":21,"max":26,"label":"Good","description":"Layout is mostly logical. Visuals are readable with minor gaps. Technical content is largely clear with small areas for improvement."},{"min":13,"max":20,"label":"Developing","description":"Occasional gaps in information flow. Some visuals are missing labels or captions. Technical content is only partially communicated."},{"min":0,"max":12,"label":"Insufficient","description":"Confusing layout. Low-quality or unlabelled visuals. Technical content is unclear or missing."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('ecc8c71e-2fca-4ab8-aaa9-9efbe29700c6', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', '3a305bed-e865-444f-a3a3-c92302bd93cf', 'delivery', 'Oral Communication', 'Oral', 'Evaluates the team''s ability to present their work verbally and to respond to questions from jurors with varying technical backgrounds. A key factor is conscious audience adaptation — adjusting depth and vocabulary based on who is asking.', 30, 30, '#3B82F6', '[{"min":27,"max":30,"label":"Excellent","description":"Presentation is consciously adapted for both technical and non-technical jury members. Q&A responses are accurate, clear, and audience-appropriate."},{"min":21,"max":26,"label":"Good","description":"Presentation is mostly clear and well-paced. Most questions answered correctly. Audience adaptation is generally evident."},{"min":13,"max":20,"label":"Developing","description":"Understandable but inconsistent. Limited audience adaptation. Time management or Q&A depth needs improvement."},{"min":0,"max":12,"label":"Insufficient","description":"Unclear or disorganised presentation. Most questions answered incorrectly or not at all."}]', 3) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('dc46db4d-fa3a-4c22-a64a-b5c07a94ebe6', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'fda374b5-0bbf-41e3-ad46-29fe1491189b', 'teamwork', 'Teamwork', 'Teamwork', 'Evaluates visible evidence of equal and effective team participation during the poster session, as well as the group''s professional and ethical conduct in interacting with jurors.', 10, 10, '#EF4444', '[{"min":9,"max":10,"label":"Excellent","description":"All members participate actively and equally. Professional and ethical conduct observed throughout."},{"min":7,"max":8,"label":"Good","description":"Most members contribute. Minor knowledge gaps. Professionalism mostly observed."},{"min":4,"max":6,"label":"Developing","description":"Uneven participation. Some members are passive or unprepared."},{"min":0,"max":3,"label":"Insufficient","description":"Very low participation or dominated by one person. Lack of professionalism observed."}]', 4) ON CONFLICT DO NOTHING;
INSERT INTO period_outcomes (id, period_id, source_outcome_id, code, label, description, sort_order) VALUES ('1f83a585-bc42-4712-a5ba-6c1ab1f8effc', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', '128e43e4-2016-4b3a-a41a-0e4856a3f593', 'MDK 1.2', 'Adequate knowledge in mathematics, science and engineering', 'Demonstrate sufficient knowledge of mathematics, natural sciences, and engineering fundamentals to solve complex engineering problems.', 1) ON CONFLICT DO NOTHING;
