INSERT INTO periods (id, organization_id, framework_id, name, season, description, start_date, end_date, is_current, is_locked, is_visible, snapshot_frozen_at, activated_at, updated_at) VALUES ('e55e0820-93f2-487f-abaa-4ae64a77e93e', 'e802a6cb-6cfa-4a7c-aba6-2038490fb899', '0147d901-984d-44c1-a08f-94f919659596', 'Spring 2025', 'Spring', 'EE Senior Design Spring — 1-Day Poster Presentations', '2025-06-11', '2025-06-11', false, true, true, (timestamp '2025-06-11 09:00:00' - interval '24 hours 0 minutes'), (timestamp '2025-06-11 09:00:00' + interval '50 hours 1 minutes'), (timestamp '2025-06-11 09:00:00' + interval '96 hours 0 minutes')) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('5c1f4f21-151a-4b22-a335-5ef961d9e99f', 'e55e0820-93f2-487f-abaa-4ae64a77e93e', 'c88501db-537c-448f-a967-fd759b41915b', 'technical', 'Technical Content', 'Technical', 'Evaluates engineering problem formulation, design methodology, and application of domain-specific knowledge.', 30, 35, '#F59E0B', '[{"min":27,"max":30,"label":"Excellent","description":"Strong problem definition with well-justified design choices. Demonstrates deep domain knowledge."},{"min":21,"max":26,"label":"Good","description":"Problem is clearly stated. Design decisions are reasonable with minor justification gaps."},{"min":13,"max":20,"label":"Developing","description":"Problem statement exists but technical depth is shallow."},{"min":0,"max":12,"label":"Insufficient","description":"Vague problem definition. Design decisions are not supported."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('15dca296-abd2-4fd9-adb3-ff2d66b91858', 'e55e0820-93f2-487f-abaa-4ae64a77e93e', '91d2ee22-2b0f-48eb-ac87-5e1fed001650', 'design', 'Written Report Quality', 'Report', 'Assesses the quality and structure of the written report including references, formatting, and technical clarity.', 30, 25, '#22C55E', '[{"min":27,"max":30,"label":"Excellent","description":"Report is well-structured with clear sections, proper references, and professional formatting."},{"min":21,"max":26,"label":"Good","description":"Report covers required sections adequately. Formatting is mostly consistent."},{"min":13,"max":20,"label":"Developing","description":"Report structure is present but sections lack depth or proper citations."},{"min":0,"max":12,"label":"Insufficient","description":"Report is incomplete, poorly formatted, or missing critical sections."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('01b94576-b441-4c66-ac35-be4aa17effa3', 'e55e0820-93f2-487f-abaa-4ae64a77e93e', '3a305bed-e865-444f-a3a3-c92302bd93cf', 'delivery', 'Oral Presentation', 'Oral', 'Evaluates oral presentation skills including confidence, pacing, audience awareness, and Q&A handling.', 30, 25, '#3B82F6', '[{"min":27,"max":30,"label":"Excellent","description":"Clear, confident delivery with good pacing. Questions answered accurately and concisely."},{"min":21,"max":26,"label":"Good","description":"Presentation is understandable with adequate pacing. Most questions handled well."},{"min":13,"max":20,"label":"Developing","description":"Delivery is hesitant or rushed. Audience engagement is limited."},{"min":0,"max":12,"label":"Insufficient","description":"Disorganized presentation. Questions frequently answered incorrectly."}]', 3) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('7a7a05a9-ac9c-402d-aa04-6a07b69dccde', 'e55e0820-93f2-487f-abaa-4ae64a77e93e', 'fda374b5-0bbf-41e3-ad46-29fe1491189b', 'teamwork', 'Teamwork', 'Teamwork', 'Assesses balanced contribution across team members and individual understanding of the project scope.', 10, 15, '#EF4444', '[{"min":9,"max":10,"label":"Excellent","description":"All members participate actively and equally. Professional and ethical conduct observed throughout."},{"min":7,"max":8,"label":"Good","description":"Most members contribute. Minor knowledge gaps. Professionalism mostly observed."},{"min":4,"max":6,"label":"Developing","description":"Uneven participation. Some members are passive or unprepared."},{"min":0,"max":3,"label":"Insufficient","description":"Very low participation or dominated by one person. Lack of professionalism observed."}]', 4) ON CONFLICT DO NOTHING;
