INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('3827321e-25d3-4ec5-ab6a-d8fb8d5f65fd', 'e77bf882-fc32-461c-acab-6ee1696df0c7', '10f52721-c639-4184-a0c4-1493bd620bfd', 'preliminary_report', 'Preliminary Design Report (ODR)', 'Report', 'Evaluates completeness of the preliminary design report, mission definition clarity, and feasibility of the proposed design.', 25, 25, '#6366F1', '[{"min":22,"max":25,"label":"Excellent","description":"Report is comprehensive with clear mission definition and feasible preliminary design."},{"min":17,"max":21,"label":"Good","description":"Report covers key design elements with adequate justification."},{"min":12,"max":16,"label":"Developing","description":"Report structure is present but design rationale is weak."},{"min":0,"max":11,"label":"Insufficient","description":"Report is incomplete or missing critical sections."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('c561d84a-3cda-4605-a33c-1ceb37ebed21', 'e77bf882-fc32-461c-acab-6ee1696df0c7', 'b58a9de4-d6c7-4143-a851-ed52ef1c7aab', 'critical_design', 'Critical Design Review (KTR)', 'CDR', 'Assesses design maturity, subsystem integration completeness, and manufacturing readiness at the CDR milestone.', 30, 30, '#F59E0B', '[{"min":27,"max":30,"label":"Excellent","description":"Design is mature, manufacturable, and all subsystems well-integrated."},{"min":21,"max":26,"label":"Good","description":"Design is mostly complete with minor integration gaps."},{"min":13,"max":20,"label":"Developing","description":"Design shows progress but subsystem integration unclear."},{"min":0,"max":12,"label":"Insufficient","description":"Design is immature or not viable for manufacturing."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('e10f1abe-f5f6-4530-ac12-708e65ef8c8f', 'e77bf882-fc32-461c-acab-6ee1696df0c7', 'a408685a-ba52-4173-a90f-b5bcf0b39b63', 'technical_performance', 'Technical Performance & Demo', 'Performance', 'Evaluates actual field performance of the system during the competition mission demonstration under real conditions.', 30, 30, '#EF4444', '[{"min":27,"max":30,"label":"Excellent","description":"System performs flawlessly in field conditions."},{"min":21,"max":26,"label":"Good","description":"System completes primary mission with minor deviations."},{"min":13,"max":20,"label":"Developing","description":"System partially completes mission."},{"min":0,"max":12,"label":"Insufficient","description":"System fails to complete primary mission."}]', 3) ON CONFLICT DO NOTHING;
