INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('93fcb76b-9827-4720-a1a8-9d65fdbc3055', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'FPGA-Based Real-Time Signal Processing for 5G NR', 1, '[{"name":"İrem Demirci","order":1},{"name":"Levent Dursun","order":2},{"name":"Azra Evren","order":3}]', 'Prof. Turgut Ercan, Dr. Ece Aydoğan', 'TED University, EE, TED University, EE', 'Implements a pipelined OFDM receiver on a Xilinx Zynq FPGA targeting 3GPP Release 17 numerology. Achieves sub-millisecond latency for channel estimation, equalization, and LDPC decoding with measured throughput exceeding 1.2 Gbps.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('46123b99-4f0a-4d61-a870-6ef0f78e371f', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'Low-Power IoT Sensor Network for Smart Agriculture', 2, '[{"name":"Ege Duran","order":1},{"name":"Dilan Aktaş","order":2},{"name":"Sinan Koç","order":3},{"name":"Melis Kavak","order":4},{"name":"Arda Keçeci","order":5}]', 'Prof. Turgut Ercan', 'TED University, EE', 'Deploys a LoRaWAN mesh of custom-designed soil-moisture and microclimate sensors across a 2-hectare test field. The STM32-based nodes achieve 18-month battery life through duty-cycled sampling and adaptive transmission intervals.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('733f9e70-8f7b-47dc-ad72-a604c760696f', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'Autonomous Drone Navigation with LiDAR SLAM', 3, '[{"name":"Şevval Güneş","order":1},{"name":"Oktay Çınar","order":2},{"name":"Gökhan Kılınç","order":3},{"name":"Oğulcan Demirel","order":4}]', 'Dr. Ece Aydoğan', 'TED University, EE', 'Integrates a Velodyne Puck LiDAR with an NVIDIA Jetson Orin for real-time 3D SLAM on a custom hexacopter. Tested in GPS-denied indoor warehouse environments with obstacle avoidance and path replanning.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('339948a9-b977-4c51-a1bd-c3dab5e32936', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'GaN Power Amplifier Design for Sub-6 GHz 5G', 4, '[{"name":"Eren Güler","order":1},{"name":"Yunus Emre Boz","order":2},{"name":"Nur Akdeniz","order":3}]', 'Prof. Cengiz Yalın, Dr. Aylin Seçkin', 'TED University, EE, TED University, EE', 'Designs and fabricates a two-stage GaN HEMT power amplifier operating at 3.5 GHz with 42 dBm output power and 68% PAE. Doherty topology enables high linearity under modulated 5G NR signals.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('2c01817f-5c28-4899-ab4b-fb741b5f8f9b', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'Biomedical Signal Processing for Sleep Apnea Detection', 5, '[{"name":"Duygu Başak","order":1},{"name":"Candan Yıldız","order":2},{"name":"Tuna Bakır","order":3}]', 'Dr. Aylin Seçkin', 'TED University, EE', 'Develops a wearable single-channel EEG acquisition board paired with a TinyML classifier running on an nRF5340 SoC. Detects obstructive sleep apnea events with 94% sensitivity validated against clinical polysomnography.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('bdb8459f-49ce-405e-af0f-d35e36fcdcf2', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'Millimeter-Wave Beamforming Antenna Array Design and Characterization for Next-Generation 5G NR FR2 Base Station Applications', 6, '[{"name":"Hazal Koç","order":1},{"name":"Efe Güneş","order":2},{"name":"Zehra Kurt","order":3},{"name":"Pelin Aydın","order":4},{"name":"Ozan Çelebi","order":5}]', 'Dr. Aylin Seçkin', 'TED University, EE', 'Designs a 16-element phased array antenna operating at 28 GHz with digital beamsteering capability. Measured beam patterns show 22 dBi gain with ±60° scanning range and -15 dB sidelobe levels.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('1449ba13-0409-4bd3-abc9-ddf7040c5b76', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'Embedded Computer Vision System for Real-Time Traffic Sign Recognition', 7, '[{"name":"Ebrar Korkmaz","order":1},{"name":"Nisa Öztürk","order":2},{"name":"Aslı Tezcan","order":3},{"name":"Sergen Koray","order":4}]', 'Prof. Tarık Özmen, Dr. Seda Bayraktar', 'TED University, EE, TED University, EE', 'Implements a lightweight CNN on an STM32H7 MCU with an OV7670 camera module for real-time traffic sign classification at 10 fps. Achieves 91% accuracy on the GTSRB dataset subset.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('9faaa31c-cdf6-4678-a123-2bfe194ce989', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'Reconfigurable Intelligent Surface Prototype for Indoor Wireless Coverage Enhancement Using Varactor-Based Unit Cells and Software-Defined Control', 8, '[{"name":"Furkan Polat","order":1},{"name":"Yiğit Polat","order":2},{"name":"Büşra Doğan","order":3},{"name":"Akın Bulut","order":4},{"name":"Doruk Acar","order":5}]', 'Dr. Seda Bayraktar', 'TED University, EE', 'Fabricates a 10x10 varactor-based RIS operating at 5.8 GHz with electronically reconfigurable reflection phase. Demonstrates 8 dB SNR improvement in an indoor NLOS scenario.') ON CONFLICT DO NOTHING;
