INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('46c52db6-2cd0-404d-a2bf-23d390c741ad', '952dd05e-8ff2-44a7-a13b-9a22958f57fb', 'MIMO Antenna Design for Indoor 5G Coverage', 2, '[{"name":"Fatih Tezel","order":1},{"name":"İrem Demirci","order":2},{"name":"Ceyda Vural","order":3},{"name":"Aslıhan Coşkun","order":4},{"name":"Oğulcan Demirel","order":5}]', 'Prof. Turgut Ercan', 'TED University, EE', 'Designs a four-element MIMO patch antenna array at 3.5 GHz with envelope correlation below 0.15, targeting small-cell indoor base stations for enhanced spatial multiplexing.') ON CONFLICT DO NOTHING;
