INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('80de3e2f-b76b-44f8-a77b-14a43979c15c', 'f8c01197-da4a-4646-a42d-8dc74715e3bc', 'Garbage Collector Comparison for JVM Languages', 4, '[{"name":"Burke Linton","order":1},{"name":"Nolan Gage","order":2},{"name":"Maren Kingsley","order":3}]', 'Dr. Amanda Torres, Prof. Michael Hoffman', 'Carnegie Mellon, LTI, Carnegie Mellon, ISR', 'Benchmarks ZGC, Shenandoah, and G1 collectors across latency-sensitive workloads (trading engine, web server), measuring pause times, throughput, and memory footprint on JDK 21.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('9a30037c-a13c-43b2-a1d1-f5d936a90409', 'f8c01197-da4a-4646-a42d-8dc74715e3bc', 'HTTP/2 Load Balancer with Health Checks', 5, '[{"name":"Harper Morgan","order":1},{"name":"Thatcher Lyle","order":2},{"name":"Rosalie Grant","order":3},{"name":"Faye Alderman","order":4},{"name":"Briar Sutton","order":5}]', 'Prof. Michael Hoffman', 'Carnegie Mellon, ISR', 'Builds a Layer-7 HTTP/2 reverse proxy in Go with weighted round-robin, connection pooling, active health probes, and graceful draining, handling 50K concurrent streams.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('d50def54-dadb-4116-a17c-0f309bbb2e5a', 'f8c01197-da4a-4646-a42d-8dc74715e3bc', 'Interactive Debugger for WebAssembly', 6, '[{"name":"Sullivan Drake","order":1},{"name":"Ronan Kirby","order":2},{"name":"Kieran Blake","order":3}]', 'Dr. Karen White', 'Carnegie Mellon, SCS', 'Extends Chrome DevTools to support source-level breakpoints, variable inspection, and call-stack navigation for Wasm modules compiled from C/Rust via DWARF debug info.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('3b8b2e62-bc66-4c8c-ad14-371049c8204e', 'e77bf882-fc32-461c-acab-6ee1696df0c7', 'Otonom Sürü İHA Takip ve Koordinasyon Sistemi', 1, '[{"name":"Nur Akdeniz","order":1},{"name":"Kübra Şen","order":2},{"name":"Ceyda Vural","order":3},{"name":"Kerem Arıcan","order":4},{"name":"Kaan Avcı","order":5}]', 'Prof. Serhat Öztürk, Dr. Fatma Korkmaz', 'İTÜ, Uçak Mühendisliği, ODTÜ, Havacılık', 'Üç adet quadrotor İHA arasında UWB haberleşme ile formasyon uçuşu gerçekleştiren otonom sürü kontrol sistemi. Lider-takipçi algoritması ile GPS-destekli rota planlaması ve engel kaçınma entegrasyonu sağlanmıştır.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('c23aa93d-d7c4-4b82-aee5-2d857b47638c', 'e77bf882-fc32-461c-acab-6ee1696df0c7', 'Yüksek İrtifa Hibrit Roket Motoru Tasarımı', 2, '[{"name":"Tolga Erim","order":1},{"name":"Sude Bulut","order":2},{"name":"Taner Özen","order":3}]', 'Prof. Serhat Öztürk', 'İTÜ, Uçak Mühendisliği', 'HTPB katı yakıt ve N₂O oksitleyici kullanan hibrit roket motorunun tasarımı, üretimi ve statik ateşleme testleri. Hedef itki profili 500 N olup, yanma odası basıncı ve özgül itki ölçümleri gerçekleştirilmiştir.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('1b122688-dc8e-467d-aa9d-16a7c8dbd1a8', 'e77bf882-fc32-461c-acab-6ee1696df0c7', 'Otonom Sualtı Aracı ile Deniz Tabanı Haritalama', 3, '[{"name":"Rıdvan Taş","order":1},{"name":"Hakan Kurt","order":2},{"name":"Atakan Yavuz","order":3},{"name":"Melis Kavak","order":4},{"name":"Dilan Aktaş","order":5}]', 'Dr. Fatma Korkmaz', 'ODTÜ, Havacılık', 'ROS2 tabanlı otonom sualtı aracı (AUV) ile sonar ve stereo kamera verisi kullanarak deniz tabanı batimetri haritası oluşturma. Dalış derinliği 30 m, navigasyon DVL ve INS füzyonu ile sağlanmıştır.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('c900eb14-5b94-461b-ac3d-f2a9075269b6', 'e77bf882-fc32-461c-acab-6ee1696df0c7', 'VTOL Sabit Kanatlı Kargo Dronu Prototipi', 4, '[{"name":"Zehra Kurt","order":1},{"name":"Duygu Başak","order":2},{"name":"Pelin Aydın","order":3},{"name":"Ezgi Nur Kavak","order":4}]', 'Dr. Fatma Korkmaz, Prof. Murat Yıldız', 'ODTÜ, Havacılık, İTÜ, Makina Mühendisliği', 'Tilt-rotor mekanizmalı VTOL sabit kanat platformu; 5 kg faydalı yük kapasitesiyle 60 km menzil hedeflenmiştir. Geçiş uçuşu kontrol algoritması Pixhawk 6X üzerinde doğrulanmıştır.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('ba5787ab-8196-4453-afd3-2e47c5185fb8', 'e77bf882-fc32-461c-acab-6ee1696df0c7', 'Radar Absorban Kompozit Kaplama Geliştirme', 5, '[{"name":"Mert Çakır","order":1},{"name":"Selçuk Taner","order":2},{"name":"Ece Yıldırım","order":3},{"name":"Zeynep Gül","order":4}]', 'Prof. Murat Yıldız', 'İTÜ, Makina Mühendisliği', 'Karbon nanotüp katkılı epoksi reçine ile X-bandı (8-12 GHz) radar absorban malzeme geliştirilmiştir. Ölçüm sonuçları -18 dB yansıma kaybı ile düşük gözlenebilirlik hedefini karşılamaktadır.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('f4598c38-54f6-4ba5-a63e-aa6efde3bd7f', 'e77bf882-fc32-461c-acab-6ee1696df0c7', 'İnsansız Kargo Gemisi Otonom Navigasyon Sistemi', 6, '[{"name":"Erdem Uzun","order":1},{"name":"Derin Alkan","order":2},{"name":"Aslıhan Coşkun","order":3},{"name":"Oğulcan Demirel","order":4},{"name":"Yaren Uçar","order":5}]', 'Prof. Murat Yıldız', 'İTÜ, Makina Mühendisliği', 'LiDAR ve AIS verileri füzyonu ile açık denizde otonom navigasyon yapan insansız yüzey aracı. COLREG kurallarına uyumlu çarpışma önleme modülü simülasyon ortamında doğrulanmıştır.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('f070dfb9-ff90-4539-afcd-c4d7c6106e95', 'e77bf882-fc32-461c-acab-6ee1696df0c7', 'Güneş Enerjili Yüksek İrtifa İHA Prototipi', 7, '[{"name":"Gökçen Aksoy","order":1},{"name":"Sena Yücel","order":2},{"name":"Altan Çevik","order":3},{"name":"Ebru Gökçe","order":4}]', 'Dr. Zehra Aksoy, Prof. Hakan Güneş', 'YTÜ, Mekatronik, Boğaziçi, Elektrik Müh.', '3 m kanat açıklığında güneş panelli sabit kanat İHA; MPPT şarj sistemi ve LiPo batarya ile 8 saat dayanıklılık hedefleyen yüksek irtifa gözetleme platformu.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('d32ea345-fbd3-4767-aacd-31c6b37a6a22', 'e77bf882-fc32-461c-acab-6ee1696df0c7', 'Akıllı Tarım Dronu ile Bitki Hastalığı Tespiti', 8, '[{"name":"Burcu Deniz","order":1},{"name":"Tuğba Erdem","order":2},{"name":"Batıkan Sevim","order":3},{"name":"Ada Toprak","order":4}]', 'Dr. Zehra Aksoy', 'YTÜ, Mekatronik', 'Multispektral kamera taşıyan tarım dronu, NDVI analizi ve CNN tabanlı görüntü sınıflandırma ile buğday tarlalarında pas hastalığını erken tespit etmektedir.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('c9c5a8d2-eda9-48e3-a011-73670f79ab2f', 'e77bf882-fc32-461c-acab-6ee1696df0c7', 'Yapay Zeka Destekli Hedef Tanıma Sistemi', 9, '[{"name":"Tuna Bakır","order":1},{"name":"Adem Yılmaztürk","order":2},{"name":"Arda Keçeci","order":3},{"name":"Merve Karaca","order":4},{"name":"Elif Yılmaz","order":5}]', 'Prof. Hakan Güneş', 'Boğaziçi, Elektrik Müh.', 'Elektro-optik gimbal kamerasından alınan video akışı üzerinde YOLOv8 tabanlı gerçek zamanlı hedef tespit ve takip sistemi. Jetson AGX Orin üzerinde 25 fps işlem hızına ulaşılmıştır.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('f134d9c5-4dbc-4e92-aa48-62f3c244de6e', 'e77bf882-fc32-461c-acab-6ee1696df0c7', 'Elektrikli VTOL Hava Taksisi Konsepti', 10, '[{"name":"Simge Kalkan","order":1},{"name":"Doruk Acar","order":2},{"name":"Defne Çetin","order":3},{"name":"Özgür Baran","order":4},{"name":"İnci Tokgöz","order":5}]', 'Prof. Hakan Güneş, Dr. Canan Eriş', 'Boğaziçi, Elektrik Müh., Eskişehir Teknik, Havacılık', 'İki kişilik elektrikli VTOL hava taksisi konsept tasarımı; aerodinamik analiz, batarya boyutlandırma ve şehir içi rota optimizasyonu CFD ve MATLAB simülasyonlarıyla gerçekleştirilmiştir.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('238b97fd-2d7a-43c5-a1a3-8fb3735867b1', 'e77bf882-fc32-461c-acab-6ee1696df0c7', 'Otonom Mayın Tespit ve İmha Robotu', 11, '[{"name":"Tarık Arslan","order":1},{"name":"Hazal Koç","order":2},{"name":"İrem Demirci","order":3},{"name":"Ozan Çelebi","order":4}]', 'Dr. Canan Eriş', 'Eskişehir Teknik, Havacılık', 'Metal dedektörü ve yer penetran radar sensörü taşıyan paletli mobil robot platformu. Otonom tarama algoritması ile 50x50 m alanda mayın tespiti ve GPS koordinat işaretleme yapılmaktadır.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('5f932d7d-ad04-44c9-ac09-459f594c1ec2', 'e77bf882-fc32-461c-acab-6ee1696df0c7', 'Karbon Fiber Gövdeli Süpersonik Model Roket', 12, '[{"name":"Gizem Aksoy","order":1},{"name":"Utku Erdem","order":2},{"name":"Berk Gündüz","order":3},{"name":"Tuğçe Can","order":4}]', 'Dr. Canan Eriş', 'Eskişehir Teknik, Havacılık', 'Karbon fiber kompozit gövdeli model roket; L sınıfı katı yakıt motoru ile Mach 1.2 hız hedeflenmiştir. Aerodinamik ısınma analizi ve fin flutter simülasyonları OpenRocket ile doğrulanmıştır.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('b6718b6b-02a8-444b-a8ec-ff82aad1b946', '308d2708-dbea-41b6-a1c8-da6129445759', 'Tarımsal İlaçlama için Çoklu Drone Filosu', 1, '[{"name":"Kübra Şen","order":1},{"name":"Sibel Acar","order":2},{"name":"İlker Durmaz","order":3},{"name":"Aslı Tezcan","order":4},{"name":"İrem Demirci","order":5}]', 'Prof. Serhat Öztürk, Dr. Fatma Korkmaz', 'İTÜ, Uçak Mühendisliği, ODTÜ, Havacılık', 'Dört hexacopter ile koordineli tarımsal ilaçlama operasyonu; otomatik şerit paylaşımı ve dolum istasyonu yönetimi ile 50 dekarlık alan 45 dakikada tamamlanmaktadır.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('75baa7d0-6001-4420-a744-5b46e6483201', '308d2708-dbea-41b6-a1c8-da6129445759', 'Sıvı Yakıtlı Model Roket ile Yükseklik Rekoru', 2, '[{"name":"Taylan Ergin","order":1},{"name":"Nur Akdeniz","order":2},{"name":"Doruk Acar","order":3},{"name":"Altan Çevik","order":4},{"name":"Çağrı Özkan","order":5}]', 'Prof. Serhat Öztürk', 'İTÜ, Uçak Mühendisliği', 'Etanol-LOX sıvı yakıtlı model roket motoru tasarımı; basınçla besleme sistemi ve özel enjektör plakası ile 3000 m irtifa hedeflenmiştir.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('35607ef7-b333-4b5b-aa1a-e7ebd1a57d32', '308d2708-dbea-41b6-a1c8-da6129445759', 'Otonom Yüzey Aracı ile Su Kalitesi İzleme', 3, '[{"name":"Ebru Gökçe","order":1},{"name":"İnci Tokgöz","order":2},{"name":"Aslıhan Coşkun","order":3},{"name":"Caner Turgut","order":4},{"name":"Duygu Başak","order":5}]', 'Dr. Fatma Korkmaz', 'ODTÜ, Havacılık', 'GPS güdümlü katamaran platformu üzerinde pH, çözünmüş oksijen ve bulanıklık sensörleri ile göl su kalitesi haritalama. Veriler LoRa ile kıyı istasyonuna aktarılmaktadır.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('accfb911-acf9-481e-a167-d4ba6eaa9aaa', '308d2708-dbea-41b6-a1c8-da6129445759', 'Dikey İniş Kalkış Teslimat Dronu', 4, '[{"name":"Ceyda Vural","order":1},{"name":"İdil Akbaş","order":2},{"name":"Mazhar Özdemir","order":3},{"name":"Yaren Uçar","order":4}]', 'Dr. Fatma Korkmaz, Prof. Murat Yıldız', 'ODTÜ, Havacılık, İTÜ, Makina Mühendisliği', 'Quad-tilt mekanizmalı teslimat dronu; 2 kg paket kapasitesi, mıknatıslı bırakma sistemi ve otomatik iniş pedine dönüş özellikleri ile 15 km menzil sağlamaktadır.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('1aad9a5e-2660-4dbe-accc-6a8612299d07', '308d2708-dbea-41b6-a1c8-da6129445759', 'Deniz Arama Kurtarma Dronu', 5, '[{"name":"Rana Keskin","order":1},{"name":"Defne Çetin","order":2},{"name":"Mert Çakır","order":3},{"name":"Ozan Çelebi","order":4},{"name":"Tuğçe Can","order":5}]', 'Prof. Murat Yıldız', 'İTÜ, Makina Mühendisliği', 'Termal kamera ve can simidi bırakma mekanizması taşıyan deniz üstü arama-kurtarma İHA platformu. Rüzgar kompanzasyonlu hovering ve otomatik arama paterni uçuşu desteklenmektedir.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('c0f554fa-594d-4490-a829-4164b21baf01', '308d2708-dbea-41b6-a1c8-da6129445759', 'Hafif Kompozit Yapılı Taktik Mini İHA', 6, '[{"name":"Tolga Erim","order":1},{"name":"Büşra Doğan","order":2},{"name":"Ebrar Korkmaz","order":3},{"name":"Nihan Sezer","order":4}]', 'Dr. Zehra Aksoy', 'YTÜ, Mekatronik', '1.2 kg kalkış ağırlığında, el fırlatmalı sabit kanat mini İHA. Kevlar-karbon hibrit yapı ve katlanır kanat mekanizması ile sırt çantasında taşınabilir tasarım.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('c76a36a7-037c-4541-ae8f-312ae44b4812', '308d2708-dbea-41b6-a1c8-da6129445759', 'Otonom Lojistik Quadcopter Sistemi', 7, '[{"name":"Cem Turgut","order":1},{"name":"Irmak Genç","order":2},{"name":"Ceren Erdoğan","order":3}]', 'Dr. Zehra Aksoy, Prof. Hakan Güneş', 'YTÜ, Mekatronik, Boğaziçi, Elektrik Müh.', 'QR kod tabanlı iniş noktası tanıma ve yük bırakma sistemi ile donatılmış lojistik quadcopter. ArduPilot Lua script ile waypoint tabanlı çoklu teslimat görevi yönetilmektedir.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('c9bb774d-0050-4605-a80d-dd3467c4836a', '308d2708-dbea-41b6-a1c8-da6129445759', 'Güdümsüz Roket Fin Stabilizasyonu', 8, '[{"name":"Batıkan Sevim","order":1},{"name":"Beren Yücel","order":2},{"name":"Korhan Alkan","order":3},{"name":"Tuna Bakır","order":4},{"name":"Kağan Erdem","order":5}]', 'Prof. Hakan Güneş', 'Boğaziçi, Elektrik Müh.', 'Model roket için pasif aerodinamik stabilizasyon amacıyla farklı fin geometrilerinin rüzgar tüneli testleri ve CFD analizleri yapılarak optimal konfigürasyon belirlenmiştir.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('399ef11e-0e5f-46cb-abfc-3fe89f900358', '308d2708-dbea-41b6-a1c8-da6129445759', 'İnsansız Yer Aracı ile Harita Çıkarma', 9, '[{"name":"Emrah Polat","order":1},{"name":"Ece Yıldırım","order":2},{"name":"Melike Savaş","order":3},{"name":"Doğukan Arslan","order":4}]', 'Prof. Hakan Güneş', 'Boğaziçi, Elektrik Müh.', 'SLAM algoritması ve stereo kamera ile iç mekan harita çıkarma yeteneğine sahip dört tekerlekli otonom kara aracı. ROS2 tabanlı navigasyon 0.5 m çözünürlüklü occupancy grid üretmektedir.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('3b331f94-7242-46a0-a427-53b72f2a2e20', '308d2708-dbea-41b6-a1c8-da6129445759', 'Topçu Düzeltme Kanatçığı Tasarımı', 10, '[{"name":"Efe Güneş","order":1},{"name":"Beyza Güler","order":2},{"name":"Görkem Taş","order":3}]', 'Dr. Canan Eriş, Prof. Serhat Öztürk', 'Eskişehir Teknik, Havacılık, İTÜ, Uçak Mühendisliği', 'Mevcut mühimmat gövdesine entegre edilebilir kanatçık kiti konsept tasarımı; servo-aktüatörlü kontrol yüzeyleri ve IMU tabanlı güdüm algoritması MATLAB ortamında simüle edilmiştir.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('4edc653f-c0e7-4217-aca1-1c827f8204aa', 'bf4ee98f-1fd2-418d-a62d-8cb5b585f293', 'Güneş Enerjili Sabit Kanatlı İHA Testi', 1, '[{"name":"Cem Turgut","order":1},{"name":"Tuğçe Can","order":2},{"name":"Zeynep Gül","order":3}]', 'Prof. Serhat Öztürk, Dr. Fatma Korkmaz', 'İTÜ, Uçak Mühendisliği, ODTÜ, Havacılık', '2 m kanat açıklığında esnek güneş hücresi kaplı sabit kanat İHA; uçuş testlerinde batarya ömrüne %40 katkı sağlayan güneş enerjisi entegrasyonu doğrulanmıştır.') ON CONFLICT DO NOTHING;
