INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('5ce62c53-1cd3-4bf4-a65b-ed5ebbe3cfaa', '3f9cabdb-61dc-45da-afa5-dbb1747cd8c8', 'Bitki Büyüme ve LED Spektrumu İlişkisi', 5, '[{"name":"Tunahan Korkut","order":1},{"name":"Rana Keskin","order":2},{"name":"Cemre Uçar","order":3},{"name":"Korhan Alkan","order":4},{"name":"Çağrı Özkan","order":5}]', 'Ahmet Çelik', 'İzmir Fen Lisesi', 'Kırmızı, mavi ve beyaz LED kombinasyonlarının marul büyüme hızı, yaprak alanı ve klorofil içeriği üzerindeki etkisi kontrollü sera ortamında 45 günlük deney ile incelenmiştir.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('2b4ffb79-4c6f-43b3-a85e-6a16da7edfdf', '3f9cabdb-61dc-45da-afa5-dbb1747cd8c8', 'Yağmur Suyu Hasadı ve Arıtım Sistemi', 6, '[{"name":"Fulya Kozan","order":1},{"name":"Sinem Uslu","order":2},{"name":"Caner Turgut","order":3}]', 'Dr. Burcu Eren', 'ODTÜ GV Lisesi', 'Çatı yüzeyinden toplanan yağmur suyunun kum-çakıl filtrasyon ve UV dezenfeksiyon ile arıtılarak sulama ve tuvalet suyu olarak kullanılabilirliği test edilmiştir.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('7c08441a-9b1c-43b1-ab4b-a6d204c8f90d', '6c44b363-4522-4cad-a251-06484b72b164', 'Phased Array Antenna for 28 GHz mmWave 5G', 1, '[{"name":"Hannah Pratt","order":1},{"name":"Dahlia Novak","order":2},{"name":"Griffin Hale","order":3},{"name":"Lucas Sullivan","order":4}]', 'Prof. Harold Kim, Dr. Sarah Novak', 'U. Michigan, ECE, Georgia Tech, ECE', 'A 16-element patch phased array on Rogers RO4003C with corporate feed network and 5-bit digital phase shifters, achieving ±45° beam scanning with 22 dBi peak gain at 28 GHz.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('ca11e01d-82af-4055-aa03-4640780aa91b', '6c44b363-4522-4cad-a251-06484b72b164', 'Wearable UHF RFID Tag Antenna for Patient Tracking', 2, '[{"name":"Charlotte Kim","order":1},{"name":"Maya Jenkins","order":2},{"name":"Andrew Holden","order":3}]', 'Prof. Harold Kim', 'U. Michigan, ECE', 'A flexible dipole-based RFID tag antenna printed on Kapton substrate, designed to operate on the human body at 915 MHz with a read range exceeding 5 m despite body-loading effects.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('f587f2b0-2c8e-40bc-ac05-182f1d07cf58', '6c44b363-4522-4cad-a251-06484b72b164', 'Dual-Band Circularly Polarized Patch for GPS/GLONASS', 3, '[{"name":"Abigail Reeves","order":1},{"name":"Gabriel Locke","order":2},{"name":"Rosalie Grant","order":3},{"name":"Merrick Towne","order":4}]', 'Prof. Harold Kim', 'U. Michigan, ECE', 'A stacked patch antenna providing RHCP at L1 (1575 MHz) and L2 (1227 MHz) with axial ratio below 2 dB across both bands, intended for precision agriculture GNSS receivers.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('32f1ec66-89dc-49f5-a867-7ec816ff6d07', '6c44b363-4522-4cad-a251-06484b72b164', 'Metamaterial Absorber for Radar Cross-Section Reduction', 4, '[{"name":"Conrad Wells","order":1},{"name":"Scarlett Wood","order":2},{"name":"Elias Boyd","order":3},{"name":"Ethan Ward","order":4}]', 'Dr. Sarah Novak, Prof. Wei Zhang', 'Georgia Tech, ECE, UCLA, EE', 'A polarization-insensitive metamaterial absorber using resistively loaded split-ring resonators, achieving greater than 90% absorption from 8 to 12 GHz for RCS reduction applications.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('5e784ee9-8ce7-4cae-a580-a07a1f11b557', '6c44b363-4522-4cad-a251-06484b72b164', 'Reconfigurable Metasurface for Beam Steering', 5, '[{"name":"Harper Morgan","order":1},{"name":"Julian Hayes","order":2},{"name":"Nolan Davies","order":3},{"name":"Zoe Powell","order":4},{"name":"Caleb Richardson","order":5}]', 'Dr. Sarah Novak', 'Georgia Tech, ECE', 'A 1-bit reconfigurable intelligent surface with PIN-diode-switched unit cells at 5.8 GHz, electronically steering a reflected beam over ±60° with measured 1.5 dB scanning loss.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('acb58410-579f-4a67-a462-68dfd1beec2e', '6c44b363-4522-4cad-a251-06484b72b164', 'Textile-Integrated Antenna Array for Body Area Networks', 6, '[{"name":"Sophie Clarke","order":1},{"name":"Sterling Cain","order":2},{"name":"Daniel Frost","order":3}]', 'Prof. Wei Zhang', 'UCLA, EE', 'A two-element conductive-thread antenna array embroidered into a polyester sports shirt, operating at 2.45 GHz for WBAN with -15 dB mutual coupling despite close inter-element spacing.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('32635f22-7ece-4fe8-a2e5-a0596659e09a', '6c44b363-4522-4cad-a251-06484b72b164', 'Frequency-Tunable Slot Antenna Using Varactor Diodes', 7, '[{"name":"Clarity Vane","order":1},{"name":"Emma Peterson","order":2},{"name":"Briar Sutton","order":3},{"name":"Clara Dawson","order":4}]', 'Prof. Wei Zhang, Dr. Anita Patel', 'UCLA, EE, Purdue, ECE', 'A CPW-fed slot antenna whose resonant frequency tunes continuously from 2.2 to 3.8 GHz via reverse-biased varactor loading, covering LTE bands 1 through 7 with a single aperture.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('07acad75-3870-4cca-a9e6-90ebcae9aa69', '6c44b363-4522-4cad-a251-06484b72b164', 'SIW-Based Diplexer for TX-RX Systems', 8, '[{"name":"Celeste Whitmore","order":1},{"name":"Jack Kelly","order":2},{"name":"Naomi Swift","order":3},{"name":"Madeline Ford","order":4},{"name":"Benjamin Cruz","order":5}]', 'Prof. Wei Zhang', 'UCLA, EE', 'A substrate-integrated-waveguide diplexer at 24/28 GHz for full-duplex mmWave front-ends, fabricated on a single Rogers 5880 layer with better than 35 dB TX-RX isolation.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('ee36879d-c1a0-4042-ae3d-4785e41a000b', '6c44b363-4522-4cad-a251-06484b72b164', 'Millimeter-Wave Lens Antenna for Automotive Radar', 9, '[{"name":"Lydia Campion","order":1},{"name":"Willa Prescott","order":2},{"name":"Pierce Dalton","order":3}]', 'Dr. Anita Patel', 'Purdue, ECE', 'A 3D-printed dielectric lens with gradient-index profile illuminated by an open-ended waveguide at 77 GHz, producing a 3° pencil beam with 28 dBi gain for long-range automotive radar.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('40a4601a-bd4f-420e-ad80-b3567e6178b3', '6c44b363-4522-4cad-a251-06484b72b164', 'Fractal Antenna for Ultra-Wideband Applications', 10, '[{"name":"Vincent Crane","order":1},{"name":"Layla Stone","order":2},{"name":"Declan Holt","order":3},{"name":"Sage Beaumont","order":4},{"name":"Beckett Thorne","order":5}]', 'Dr. Anita Patel, Prof. Gregory Harmon', 'Purdue, ECE, Ohio State, ECE', 'A Minkowski-island fractal monopole printed on FR-4, covering 3.1 to 10.6 GHz with VSWR below 2:1 and a compact footprint 40% smaller than a conventional UWB disc monopole.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('558f6b14-f11f-4dc3-ad37-c9041ad4e145', '318124ea-8614-4355-ad48-2486524dfc13', 'Reconfigurable FSS for 5G Shielding', 1, '[{"name":"Rhys Davenport","order":1},{"name":"Penelope Blake","order":2},{"name":"James Thornton","order":3},{"name":"Sienna West","order":4},{"name":"Charlotte Kim","order":5}]', 'Prof. Harold Kim, Dr. Sarah Novak', 'U. Michigan, ECE, Georgia Tech, ECE', 'A frequency-selective surface with PIN-diode-switchable unit cells that toggles between pass and stop states at 3.5 GHz, enabling on-demand electromagnetic shielding for secure rooms.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('e970c78e-aaff-43ef-a236-77caf54b07ce', '318124ea-8614-4355-ad48-2486524dfc13', 'Compact MIMO Antenna for Sub-6 GHz Handsets', 2, '[{"name":"Lucas Sullivan","order":1},{"name":"Zoe Powell","order":2},{"name":"Gabriel Locke","order":3},{"name":"Mabel Trent","order":4}]', 'Prof. Harold Kim', 'U. Michigan, ECE', 'A four-port MIMO antenna occupying 150x75 mm using orthogonal slot modes to achieve ECC below 0.05 across 3.3-3.8 GHz for 5G smartphone integration.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('9c450cf6-cae4-4390-a3ed-12f231962d02', '318124ea-8614-4355-ad48-2486524dfc13', 'SIW Filter for Ka-Band', 3, '[{"name":"Ivy Sheridan","order":1},{"name":"Elias Boyd","order":2},{"name":"Sebastian Cross","order":3},{"name":"Alexander Dunn","order":4},{"name":"Clara Dawson","order":5}]', 'Dr. Sarah Novak', 'Georgia Tech, ECE', 'A fourth-order Chebyshev bandpass filter implemented in SIW at 26 GHz with 800 MHz bandwidth, 1.2 dB insertion loss, and 25 dB rejection at ±1.5 GHz offset.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('985b9ce9-1302-4ed5-ac37-74f7c3eebfc5', '318124ea-8614-4355-ad48-2486524dfc13', 'Broadband Log-Periodic for EMC Testing', 4, '[{"name":"Brynn Ellery","order":1},{"name":"Abigail Reeves","order":2},{"name":"Nolan Davies","order":3},{"name":"Tessa Marlow","order":4},{"name":"Dylan Reed","order":5}]', 'Dr. Sarah Novak, Prof. Wei Zhang', 'Georgia Tech, ECE, UCLA, EE', 'A printed log-periodic dipole array covering 200 MHz to 6 GHz for pre-compliance EMC measurements, with calibrated gain data traceable to a reference horn antenna.') ON CONFLICT DO NOTHING;
