INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('bc3fe67d-937f-4744-ae90-a19293fc5d5c', 'b7014c23-db5e-4be5-a5d6-d9597e8578cc', 'Flexible Inkjet-Printed Antenna for Wearable IoT', 2, '[{"name":"Mason Bell","order":1},{"name":"Freya Langston","order":2},{"name":"Aria Sanders","order":3}]', 'Prof. Harold Kim', 'U. Michigan, ECE', 'A silver-nanoparticle inkjet-printed meander-line antenna on PET film, resonating at 2.45 GHz with -12 dBi gain, surviving 500 bend cycles to a 15 mm radius.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('e819a48d-0cd4-4027-aa05-4c5458518283', 'b7014c23-db5e-4be5-a5d6-d9597e8578cc', 'Patch Antenna Array for 24 GHz Doppler Radar', 3, '[{"name":"Leo Gallagher","order":1},{"name":"Barrett Fox","order":2},{"name":"Alice Brennan","order":3}]', 'Dr. Sarah Novak', 'Georgia Tech, ECE', 'A 2x4 series-fed patch array on Rogers 5880 for K-band CW Doppler radar, providing 18 dBi gain with a fan beam for traffic speed measurement.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('ab1fc3ab-1121-4eac-a869-537be94d5d4f', 'b7014c23-db5e-4be5-a5d6-d9597e8578cc', 'Wearable Antenna for UHF Emergency Comm', 4, '[{"name":"Matthew Doyle","order":1},{"name":"Stella Myers","order":2},{"name":"Elise Whitfield","order":3},{"name":"June Holbrook","order":4}]', 'Dr. Sarah Novak, Prof. Wei Zhang', 'Georgia Tech, ECE, UCLA, EE', 'A flexible inverted-F antenna integrated into a firefighter jacket collar, operating at 430 MHz with ground-plane independence verified through on-body measurements.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('48863d9f-885f-4f71-a929-d3313626b41b', 'b7014c23-db5e-4be5-a5d6-d9597e8578cc', 'Compact Loop Antenna for NFC/WPT', 5, '[{"name":"Connor Ross","order":1},{"name":"Jasper Voss","order":2},{"name":"Keira Stanton","order":3},{"name":"Callum Harding","order":4}]', 'Prof. Wei Zhang', 'UCLA, EE', 'A planar spiral-loop antenna at 13.56 MHz optimized for simultaneous NFC data transfer and 2W wireless power transfer to wearable medical devices.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('dcfe3392-61a2-44e1-ae05-da975e5f46a2', 'b7014c23-db5e-4be5-a5d6-d9597e8578cc', 'Printed Yagi-Uda for Direction Finding', 6, '[{"name":"Rosalie Grant","order":1},{"name":"Samuel Rivera","order":2},{"name":"Madeline Ford","order":3},{"name":"Burke Linton","order":4},{"name":"Leona Stratton","order":5}]', 'Dr. Anita Patel', 'Purdue, ECE', 'A five-element printed Yagi-Uda at 900 MHz with 9 dBi gain and 50° HPBW, used as the element in a four-quadrant DF array for wildlife VHF collar tracking.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('f94e5535-1e54-429d-aa5b-bec1b4b89523', 'b0cb348c-59b5-407f-a21e-e6d514d0dd4b', 'Autogyro Descent and Precision Landing System', 1, '[{"name":"Sawyer Pace","order":1},{"name":"Charlotte Kim","order":2},{"name":"Dylan Reed","order":3},{"name":"Olivia Chen","order":4},{"name":"Lucy Brooks","order":5}]', 'Prof. Richard Kline, Dr. Samantha Ford', 'Virginia Tech, Aerospace, MIT, AeroAstro', 'Replaces the traditional parachute with a folding autogyro rotor blade assembly that deploys at apogee. Achieves a controlled 5 m/s descent rate with GPS-guided heading corrections targeting a 10 m landing circle.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('979705de-bf63-46d1-a3ef-b1ec2bac8db0', 'b0cb348c-59b5-407f-a21e-e6d514d0dd4b', 'Dual-Redundant Telemetry with LoRa Failover', 2, '[{"name":"Naomi Swift","order":1},{"name":"Benjamin Cruz","order":2},{"name":"Dominic Hurst","order":3},{"name":"Vincent Crane","order":4},{"name":"Sophia Linden","order":5}]', 'Prof. Richard Kline', 'Virginia Tech, Aerospace', 'Primary telemetry uses 915 MHz FSK at 19.2 kbps; a secondary LoRa channel activates automatically if packet loss exceeds 20%, ensuring continuous data downlink throughout the 600 m descent.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('9e398895-956e-4281-a94d-e7f429a5ebda', 'b0cb348c-59b5-407f-a21e-e6d514d0dd4b', 'Multi-Sensor Atmospheric Profiling Payload', 3, '[{"name":"Freya Langston","order":1},{"name":"Alina Frost","order":2},{"name":"Aurora Price","order":3},{"name":"Lucas Sullivan","order":4}]', 'Prof. Richard Kline', 'Virginia Tech, Aerospace', 'Carries BME680, SCD41, and UV-B sensors to build a vertical atmospheric profile of temperature, humidity, CO₂, and UV irradiance from 700 m AGL to ground, sampled at 10 Hz.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('6dd97497-6e0a-4f30-a2f2-c406ece91418', 'b0cb348c-59b5-407f-a21e-e6d514d0dd4b', 'Deployable Aerobrake Heat Shield Demonstrator', 4, '[{"name":"Astrid Lyons","order":1},{"name":"Declan Holt","order":2},{"name":"Alice Brennan","order":3},{"name":"Miles Cunningham","order":4}]', 'Dr. Samantha Ford, Prof. Douglas Park', 'MIT, AeroAstro, CU Boulder, Aerospace', 'A spring-loaded deployable drag device made from Nomex fabric and carbon-fiber ribs, demonstrating controlled deceleration from 30 m/s to 8 m/s within the first 200 m of descent.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('3be8e1f3-a431-4946-a139-dad5f27ac5db', 'b0cb348c-59b5-407f-a21e-e6d514d0dd4b', 'Split-Body CanSat with Wireless Inter-Module Telemetry', 5, '[{"name":"Maya Jenkins","order":1},{"name":"Davis Carver","order":2},{"name":"Fletcher Byrne","order":3}]', 'Dr. Samantha Ford', 'MIT, AeroAstro', 'The CanSat separates at apogee into a sensor pod and a gliding recovery vehicle, communicating via a 2.4 GHz radio link. Both modules transmit independent telemetry to the ground station.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('137d41fc-0de0-44fc-aa5f-64c90ed72d97', 'b0cb348c-59b5-407f-a21e-e6d514d0dd4b', 'GNSS-Denied Navigation Using Barometric-IMU Fusion', 6, '[{"name":"Burke Linton","order":1},{"name":"Abigail Reeves","order":2},{"name":"Ella Brooks","order":3}]', 'Prof. Douglas Park', 'CU Boulder, Aerospace', 'Demonstrates position estimation during simulated GPS jamming by fusing barometric altitude, 9-DOF IMU data, and a terrain-referenced navigation algorithm with 15 m CEP accuracy.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('5160ae52-aa8f-44d2-a539-d718b6188111', 'b0cb348c-59b5-407f-a21e-e6d514d0dd4b', 'Thermal Imaging Mission for Wildfire Detection', 7, '[{"name":"June Holbrook","order":1},{"name":"Zoe Powell","order":2},{"name":"Tessa Rowan","order":3},{"name":"Adam Bennett","order":4},{"name":"Leo Gallagher","order":5}]', 'Prof. Douglas Park, Dr. Yuki Tanaka', 'CU Boulder, Aerospace, Caltech, GALCIT', 'Mounts a FLIR Lepton 3.5 thermal camera to detect ground hotspots during descent, processing thermal frames on an RP2040 to flag anomalies and geotag them with concurrent GPS fixes.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('3f31495c-73ea-4118-a2c9-b7d1afc7ba03', 'b0cb348c-59b5-407f-a21e-e6d514d0dd4b', 'Controlled Descent Using Active Fin Steering', 8, '[{"name":"Ada Carrington","order":1},{"name":"Maeve Alcott","order":2},{"name":"Willa Prescott","order":3},{"name":"Stella Myers","order":4},{"name":"Cole Harrison","order":5}]', 'Prof. Douglas Park', 'CU Boulder, Aerospace', 'Four servo-actuated fins provide roll and pitch control during parachute descent, guided by a PID controller tracking GPS waypoints to steer the CanSat toward a designated landing zone.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('3773bd26-cbbf-482a-a997-598f289750ec', 'b0cb348c-59b5-407f-a21e-e6d514d0dd4b', 'Radiation Dosimetry for High-Altitude Profiling', 9, '[{"name":"Gabriel Locke","order":1},{"name":"Colton Sawyer","order":2},{"name":"Emmett Lawson","order":3},{"name":"Emma Peterson","order":4},{"name":"Iris Mercer","order":5}]', 'Dr. Yuki Tanaka', 'Caltech, GALCIT', 'A Geiger-Muller tube and SiPM-based scintillator measure ionizing radiation dose rate from launch to landing, building a vertical dose profile relevant to aviation and balloon missions.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('e9b35bef-d3c5-4eb4-a93a-76bc2e14f64a', 'b0cb348c-59b5-407f-a21e-e6d514d0dd4b', 'AI-Powered Image Classification During Descent', 10, '[{"name":"Royce Hendrix","order":1},{"name":"Beau Garrett","order":2},{"name":"Wren Ellsworth","order":3},{"name":"Nadia Glenn","order":4}]', 'Dr. Yuki Tanaka, Prof. Brian Caldwell', 'Caltech, GALCIT, Purdue, AAE', 'A downward-facing camera captures terrain images during descent, classified on-board by a TensorFlow Lite model into land-cover categories (vegetation, water, urban, bare soil) and transmitted in real time.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('892ff2fd-a88a-4e86-ae49-9c8063d9eec9', 'c8021bb8-fd12-4826-a314-7139a5971fe5', 'Parafoil Guided Recovery with GPS Waypoints', 1, '[{"name":"Leo Gallagher","order":1},{"name":"Harlow Sinclair","order":2},{"name":"Sienna West","order":3},{"name":"Emma Peterson","order":4},{"name":"Scarlett Wood","order":5}]', 'Prof. Richard Kline, Dr. Samantha Ford', 'Virginia Tech, Aerospace, MIT, AeroAstro', 'A ram-air parafoil with servo-controlled brake toggles guides the CanSat through four GPS waypoints during descent, achieving a 25 m landing accuracy in field tests.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('15d8cf36-7f19-4089-af96-15f16df22d1a', 'c8021bb8-fd12-4826-a314-7139a5971fe5', 'Solar-Powered Secondary Mission: UV Index Mapping', 2, '[{"name":"Nadia Glenn","order":1},{"name":"Lucas Sullivan","order":2},{"name":"Maya Jenkins","order":3},{"name":"Aria Sanders","order":4},{"name":"Felix Palmer","order":5}]', 'Prof. Richard Kline', 'Virginia Tech, Aerospace', 'Thin-film solar cells supplement the battery during descent while a VEML6075 UV sensor maps UV-A and UV-B intensity at 5 m altitude increments for atmospheric research.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('a9903c1c-c222-4edd-a114-924f76de4cbe', 'c8021bb8-fd12-4826-a314-7139a5971fe5', 'Deployable Boom Magnetometer Suite', 3, '[{"name":"Rhys Davenport","order":1},{"name":"Landon Howe","order":2},{"name":"Hayes Drummond","order":3},{"name":"Oscar Quinn","order":4},{"name":"Ronan Kirby","order":5}]', 'Dr. Samantha Ford', 'MIT, AeroAstro', 'A 30 cm spring-loaded boom extends after ejection to distance a fluxgate magnetometer from the CanSat electronics, measuring geomagnetic field variation with 10 nT resolution.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('ae981e74-8446-4c5b-a923-bf62251eae9e', 'c8021bb8-fd12-4826-a314-7139a5971fe5', 'Hydrogen Fuel Cell Ground Recovery Vehicle', 4, '[{"name":"Camille Darrow","order":1},{"name":"Isla Webb","order":2},{"name":"Grace Kelly","order":3}]', 'Dr. Samantha Ford, Prof. Douglas Park', 'MIT, AeroAstro, CU Boulder, Aerospace', 'A PEM fuel-cell-powered rover navigates to the CanSat landing coordinates using GPS, retrieves the payload, and returns to the launch site autonomously.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('420ef787-d53a-4b6d-a780-2ec33f3a056e', 'c8021bb8-fd12-4826-a314-7139a5971fe5', 'Dual-Camera Stereoscopic Terrain Mapping', 5, '[{"name":"Wren Ellsworth","order":1},{"name":"Eleanor Marsh","order":2},{"name":"Conrad Wells","order":3},{"name":"Spencer Leigh","order":4},{"name":"Miles Cunningham","order":5}]', 'Prof. Douglas Park', 'CU Boulder, Aerospace', 'Two synchronized OV5640 cameras capture stereo image pairs during descent, processed on the ground into a 3D point cloud for terrain reconstruction of the landing area.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('72872b7f-05a8-4b8e-a4fa-8609e094deb5', 'c8021bb8-fd12-4826-a314-7139a5971fe5', 'CanSat-to-CanSat Mesh Communication', 6, '[{"name":"Chloe Ward","order":1},{"name":"Naomi Swift","order":2},{"name":"Tristan Blake","order":3}]', 'Prof. Douglas Park', 'CU Boulder, Aerospace', 'Two CanSats launched in sequence form a 900 MHz mesh relay, extending telemetry range by 60% and demonstrating multi-node swarm communication for future missions.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('a0c9f631-76eb-4792-a97b-1119d9c922e2', 'c8021bb8-fd12-4826-a314-7139a5971fe5', 'Biodegradable Structure CanSat Design', 7, '[{"name":"Sawyer Pace","order":1},{"name":"Logan Bailey","order":2},{"name":"Avery James","order":3},{"name":"Sophie Clarke","order":4},{"name":"Thatcher Lyle","order":5}]', 'Dr. Yuki Tanaka, Prof. Brian Caldwell', 'Caltech, GALCIT, Purdue, AAE', 'The airframe is constructed from PLA and mycelium composite panels that fully biodegrade within 90 days, addressing environmental concerns for CanSats that cannot be recovered.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('689891c8-d871-4296-abeb-227eadf62b4c', 'c8021bb8-fd12-4826-a314-7139a5971fe5', 'Acoustic Wind Profiling Payload', 8, '[{"name":"Ada Carrington","order":1},{"name":"Odette Marsh","order":2},{"name":"Lennox Gray","order":3},{"name":"Burke Linton","order":4},{"name":"Dillon Kane","order":5}]', 'Dr. Yuki Tanaka', 'Caltech, GALCIT', 'Four MEMS microphones arranged in a tetrahedral array measure wind speed and direction during descent via time-of-arrival acoustic anemometry, providing 1 Hz wind profiles.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('1e06975f-2719-4d20-af72-463523414cc5', 'fc0d4911-6a79-4e75-a385-e5d852fc6dd0', 'Maple-Seed Inspired Passive Descent Vehicle', 1, '[{"name":"Elise Whitfield","order":1},{"name":"Nolan Davies","order":2},{"name":"Charlotte Kim","order":3},{"name":"Caleb Richardson","order":4},{"name":"Elias Boyd","order":5}]', 'Prof. Richard Kline, Dr. Samantha Ford', 'Virginia Tech, Aerospace, MIT, AeroAstro', 'A single-blade autorotation design inspired by maple samaras achieves a stable 4 m/s descent without active control, with the spin rate providing attitude stabilization.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('c320c5c3-24de-4b52-a7c1-2c0ccaa8dfef', 'fc0d4911-6a79-4e75-a385-e5d852fc6dd0', 'Ground Station with Real-Time 3D Trajectory', 2, '[{"name":"Leo Gallagher","order":1},{"name":"Madeline Ford","order":2},{"name":"Oscar Quinn","order":3},{"name":"Sienna West","order":4},{"name":"Tristan Blake","order":5}]', 'Prof. Richard Kline', 'Virginia Tech, Aerospace', 'A Python/Qt ground station application receives 10 Hz telemetry and renders the CanSat trajectory in a 3D map view with altitude, velocity, and orientation overlays.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('9b7e183b-5da5-4260-a554-9e7758248af7', 'fc0d4911-6a79-4e75-a385-e5d852fc6dd0', 'Glider Recovery with Autonomous Steering', 3, '[{"name":"Kieran Blake","order":1},{"name":"Isaac Perez","order":2},{"name":"Cole Harrison","order":3},{"name":"Grace Kelly","order":4},{"name":"Nathan Cox","order":5}]', 'Dr. Samantha Ford', 'MIT, AeroAstro', 'The CanSat transitions to a fixed-wing glider configuration after parachute release, autonomously steering toward the launch site using proportional navigation guidance.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('cb967b3a-8188-455d-a009-0d7abbe74916', 'fc0d4911-6a79-4e75-a385-e5d852fc6dd0', 'LoRa Long-Range Telemetry Ground Station', 4, '[{"name":"Naomi Swift","order":1},{"name":"Beckett Thorne","order":2},{"name":"Jasper Voss","order":3},{"name":"Piper York","order":4}]', 'Dr. Samantha Ford, Prof. Douglas Park', 'MIT, AeroAstro, CU Boulder, Aerospace', 'A high-gain Yagi antenna and LoRa receiver achieve reliable telemetry reception at 8 km range using spreading factor 10 at 868 MHz with forward error correction.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('f55beb55-2fc0-4202-a32a-9dfac0825f5c', 'fc0d4911-6a79-4e75-a385-e5d852fc6dd0', 'Atmospheric Particulate Matter Sampling', 5, '[{"name":"June Holbrook","order":1},{"name":"Gemma Whitlock","order":2},{"name":"Nolan Gage","order":3},{"name":"Jensen Holt","order":4},{"name":"Royce Hendrix","order":5}]', 'Prof. Douglas Park', 'CU Boulder, Aerospace', 'A miniature impactor sampler collects PM2.5 and PM10 particles on adhesive substrate during descent, analyzed post-flight under a microscope for morphology and composition.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('8031440f-0ead-41e4-affe-8dc22de71f9f', 'fc0d4911-6a79-4e75-a385-e5d852fc6dd0', 'Parachute Deployment Optimization via ML', 6, '[{"name":"Everett Moon","order":1},{"name":"Julian Hayes","order":2},{"name":"Henry Torres","order":3},{"name":"Mia Howard","order":4},{"name":"Eleanor Marsh","order":5}]', 'Dr. Yuki Tanaka', 'Caltech, GALCIT', 'A random-forest model trained on 200 simulation runs predicts optimal parachute deployment altitude based on real-time wind and descent-rate data, minimizing landing dispersion.') ON CONFLICT DO NOTHING;
