INSERT INTO jury_feedback (period_id, juror_id, rating, comment, is_public, created_at) VALUES
('a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'aaa0da50-6432-47e0-ab48-b01ca823ef19', 4, NULL, false, (timestamp '2026-06-11 09:00:00' + interval '10 hours 3 minutes')),
('a0d6f60d-ece4-40f8-aca2-955b4abc5d88', '9a21397b-552a-4b00-a5c4-15a0982436b1', 5, 'Very practical system. We completed all evaluations on poster day without any issues.', true, (timestamp '2026-06-11 09:00:00' + interval '8 hours 31 minutes')),
('a0d6f60d-ece4-40f8-aca2-955b4abc5d88', '868057b9-f2e0-4db1-a4e9-e258d25f84e1', 4, 'Clean interface with fast response. The rubric bands were extremely helpful.', true, (timestamp '2026-06-11 09:00:00' + interval '9 hours 2 minutes')),
('a0d6f60d-ece4-40f8-aca2-955b4abc5d88', '56948fec-ce3d-493b-afc4-4e281e9b8f58', 3, 'Decent tool overall, but the mobile layout could use improvement for tablet users.', true, (timestamp '2026-06-11 09:00:00' + interval '16 hours 54 minutes')),
('a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'b43a5dc5-d587-4940-a4ab-7d8a7ed44387', 3, 'The summary view made it easy to catch inconsistencies.', true, (timestamp '2026-06-11 09:00:00' + interval '9 hours 27 minutes')),
('a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'd061174f-dbec-4d68-a56d-ce41cdc205a6', 2, NULL, false, (timestamp '2026-06-11 09:00:00' + interval '13 hours 4 minutes')),
('a0d6f60d-ece4-40f8-aca2-955b4abc5d88', '8d2ec406-10bd-4d30-ab5d-c3841540ddf2', 5, NULL, true, (timestamp '2026-06-11 09:00:00' + interval '16 hours 16 minutes')),
('a0d6f60d-ece4-40f8-aca2-955b4abc5d88', '00f1f6a9-f69d-438a-a256-b2f9369c7559', 3, 'The summary view made it easy to catch inconsistencies.', true, (timestamp '2026-06-11 09:00:00' + interval '4 hours 18 minutes')),
('a0d6f60d-ece4-40f8-aca2-955b4abc5d88', '4118fb7f-a6aa-4b28-a6d1-5eb668e4bd66', 4, 'Worked well on mobile — no installation needed.', false, (timestamp '2026-06-11 09:00:00' + interval '8 hours 50 minutes')),
